// 根据 source URL 获取英文原文的辅助函数
function getEnglishText(sourceUrl) {
  if (!sourceUrl) return null
  // 从 URL 提取最后的路径段作为 key
  const key = sourceUrl.split('/').pop()
  return extraStoriesEn[key] || null
}

export { extraStoriesEn, getEnglishText }
